import { useForm } from 'react-hook-form';
import RichTextEditor from '@/components/shared/RichTextEditor';

const { register, handleSubmit, setValue, formState: { errors } } = useForm();

const onSubmit = (data) => {
  console.log('Content:', data.content);
};

<form onSubmit={handleSubmit(onSubmit)}>
  <RichTextEditor
    content=""
    invalid={!!errors.content}
    onChange={({ html, text }) => {
      setValue('content', html);
      // Validate minimum length
      if (text.trim().length < 10) {
        setError('content', { message: 'Content too short' });
      } else {
        clearErrors('content');
      }
    }}
  />
  {errors.content && (
    <p className="text-error text-sm mt-1">{errors.content.message}</p>
  )}
  <Button type="submit">Submit</Button>
</form>

import { useEditor } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import Image from '@tiptap/extension-image';
import Link from '@tiptap/extension-link';
import Placeholder from '@tiptap/extension-placeholder';
import RichTextEditor from '@/components/shared/RichTextEditor';

const editor = useEditor({
  extensions: [
    StarterKit,
    Image.configure({
      inline: true,
      allowBase64: true,
    }),
    Link.configure({
      openOnClick: false,
    }),
    Placeholder.configure({
      placeholder: 'Write something amazing...',
    }),
  ],
  content: '<p>Hello World!</p>',
  onUpdate({ editor }) {
    console.log('Content updated:', editor.getHTML());
  },
});

if (!editor) return <div>Loading editor...</div>;

<RichTextEditor
  customEditor={editor}
  customToolBar={(editor, components) => (
    <div className="flex gap-2">
      <components.ToolButtonBold editor={editor} />
      <components.ToolButtonItalic editor={editor} />
      <components.ToolButtonHeading editor={editor} />
      {/* Add custom image button */}
      <ToolButtonImage editor={editor} onUpload={handleImageUpload} />
      {/* Add custom link button */}
      <ToolButtonLink editor={editor} />
    </div>
  )}
/>

